// NODO: Final_Draft_Response
// OBIETTIVO: Formattare la risposta per la WebApp e gestire errori AI

try {
  const item = $input.first().json;

  // 1. VALIDAZIONE INPUT
  // Controlliamo se Gemini ha effettivamente generato la struttura richiesta
  if (!item.product_structure || !item.product_structure.catalog_item_draft) {
    throw new Error("Struttura JSON mancante nell'output AI");
  }

  const draft = item.product_structure.catalog_item_draft;
  const uiNode = item.product_structure.ui_node_draft;

  // 2. PREPARAZIONE PAYLOAD (Successo)
  // Appiattiamo la struttura affinché la WebApp trovi subito 'data.identity'
  return {
    json: {
      success: true, // Flag per il frontend

      // Dati Prodotto (Identity, Pricing, Operations...)
      ...draft, 

      // Dati UI (per anteprima o logica futura)
      ui_node_draft: uiNode,

      // Gestione Duplicati (Passiamo solo i dati, la WebApp traduce il messaggio)
      is_duplicate: draft.metadata.is_duplicate || false,
      duplicate_id: draft.metadata.duplicate_of || null
    }
  };

} catch (error) {
  // 3. GESTIONE ERRORI (Graceful Fail)
  // Se qualcosa va storto, non mandiamo un crash n8n, ma un JSON di errore
  // così la WebApp può dire "Riprova" invece di andare in timeout.
  return {
    json: {
      success: false,
      error: true,
      message: "Errore nella generazione della bozza.",
      details: error.message
    }
  };
}

